const e="lengua",a=JSON.parse(`[{"id":"lengua-001","front":"¿Qué es la coherencia textual?","back":"Es la propiedad por la que un texto presenta unidad de sentido y una organización lógica de sus ideas, sin contradicciones internas.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-002","front":"¿Qué es la cohesión textual?","back":"Es la propiedad que conecta las partes de un texto mediante mecanismos lingüísticos como conectores, repeticiones, pronombres o tiempos verbales.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-003","front":"¿Qué es la adecuación en un texto?","back":"Es la adaptación del discurso a la situación comunicativa, al destinatario, al canal y a la intención del emisor.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-004","front":"¿Qué son los marcadores textuales?","back":"Son palabras o expresiones que organizan el discurso y guían la interpretación del texto: por ejemplo, 'además', 'sin embargo' o 'por tanto'.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-005","front":"¿Qué caracteriza a un texto expositivo?","back":"Su finalidad principal es informar o explicar un tema de forma clara, ordenada y objetiva.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-006","front":"¿Qué caracteriza a un texto argumentativo?","back":"Defiende una tesis mediante razones, ejemplos y argumentos con intención de persuadir o convencer al receptor.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-007","front":"¿Qué es la intención comunicativa de un texto?","back":"Es la finalidad que persigue el emisor al producirlo: informar, opinar, persuadir, denunciar, emocionar o explicar, entre otras.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-008","front":"¿Qué debe identificarse primero en un comentario de texto?","back":"Las ideas principales y secundarias, porque permiten entender el sentido global y la organización del texto.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-009","front":"¿Qué es la subjetividad en un texto?","back":"Es la presencia de la opinión, la valoración o la actitud personal del emisor mediante recursos lingüísticos expresivos.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-010","front":"¿Qué es la objetividad en un texto?","back":"Es la presentación de la información con apariencia neutral, sin valoración explícita del emisor y con predominio de datos o hechos.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-011","front":"¿Qué rasgo suele indicar subjetividad en un texto?","back":"El uso de adjetivos valorativos, modalizadores, primera persona o expresiones de opinión como 'creo', 'sin duda' o 'lamentablemente'.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-012","front":"¿Qué rasgo suele indicar objetividad en un texto?","back":"El uso de tercera persona, léxico denotativo, datos verificables, construcciones impersonales y tono neutro.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-013","front":"¿Qué función tienen los signos de puntuación en un texto escrito?","back":"Organizan el discurso, marcan relaciones sintácticas y ayudan a precisar el significado y la interpretación.","topic":"Comentario de texto","difficulty":1,"fromOrientaciones":true},{"id":"lengua-014","front":"¿Qué es un texto multimodal?","back":"Es un texto que combina varios códigos de comunicación, como palabras, imágenes, sonidos, tipografía o elementos audiovisuales.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-015","front":"¿Qué caracteriza al texto científico?","back":"Presenta información especializada con precisión, objetividad, claridad y uso frecuente de tecnicismos.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-016","front":"¿Qué caracteriza al texto humanístico?","back":"Reflexiona sobre temas humanos, sociales o culturales con mayor presencia de interpretación, abstracción y argumentación.","topic":"Tipos de textos","difficulty":2,"fromOrientaciones":true},{"id":"lengua-017","front":"¿Qué es un ensayo?","back":"Es un texto en prosa de carácter reflexivo y argumentativo en el que el autor expone e interpreta un tema desde una perspectiva personal.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-018","front":"¿Qué distingue al artículo periodístico de opinión?","back":"Su finalidad es interpretar o valorar hechos de actualidad desde el punto de vista del autor, no solo informar sobre ellos.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-019","front":"¿Qué busca la publicidad como género discursivo?","back":"Persuadir al receptor para que adopte una conducta, normalmente consumir un producto, apoyar una idea o modificar una actitud.","topic":"Tipos de textos","difficulty":1,"fromOrientaciones":true},{"id":"lengua-020","front":"¿Qué debe tenerse en cuenta al analizar una red social como discurso?","back":"La brevedad, la inmediatez, la multimodalidad, la interacción con usuarios y la mezcla de registros y finalidades comunicativas.","topic":"Tipos de textos","difficulty":2,"fromOrientaciones":true},{"id":"lengua-021","front":"¿Qué es la cortesía lingüística?","back":"Es el conjunto de estrategias verbales que suavizan el discurso y favorecen una interacción respetuosa entre interlocutores.","topic":"Pragmática","difficulty":1,"fromOrientaciones":true},{"id":"lengua-022","front":"¿Qué significa tomar y ceder la palabra en una interacción oral?","back":"Regular los turnos de habla de forma cooperativa para mantener una conversación ordenada y eficaz.","topic":"Pragmática","difficulty":1,"fromOrientaciones":true},{"id":"lengua-023","front":"¿Qué es la cooperación conversacional?","back":"Es el principio por el que los hablantes contribuyen al intercambio comunicativo de forma pertinente, clara y suficiente.","topic":"Pragmática","difficulty":2,"fromOrientaciones":true},{"id":"lengua-024","front":"¿Qué es la alfabetización informacional?","back":"Es la capacidad de buscar, seleccionar, evaluar, reorganizar y comunicar información con criterios de fiabilidad, calidad y pertinencia.","topic":"Comunicación","difficulty":2,"fromOrientaciones":true},{"id":"lengua-025","front":"¿Qué es una noticia falsa o 'fake news'?","back":"Es un contenido engañoso que aparenta ser verdadero y circula como información, aunque carece de base fiable.","topic":"Comunicación","difficulty":1,"fromOrientaciones":true},{"id":"lengua-026","front":"¿Por qué es importante verificar hechos en un texto informativo?","back":"Porque permite comprobar la veracidad de los datos y evitar la difusión de errores, bulos o manipulaciones.","topic":"Comunicación","difficulty":1,"fromOrientaciones":true},{"id":"lengua-027","front":"¿Qué es el registro lingüístico?","back":"Es la variedad de lengua que se elige según la situación comunicativa, el grado de formalidad y la relación entre interlocutores.","topic":"Las lenguas y sus hablantes","difficulty":1,"fromOrientaciones":true},{"id":"lengua-028","front":"¿Qué diferencia hay entre dialecto y registro?","back":"El dialecto depende del territorio o la comunidad lingüística; el registro depende de la situación comunicativa y del contexto de uso.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-029","front":"¿Qué son los sociolectos?","back":"Son variedades lingüísticas asociadas a grupos sociales definidos por factores como edad, nivel educativo o profesión.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-030","front":"¿Qué son los tecnolectos?","back":"Son variedades especializadas de la lengua propias de ámbitos técnicos o profesionales, con abundancia de terminología específica.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-031","front":"¿Qué son las jergas?","back":"Son usos lingüísticos propios de determinados grupos sociales o profesionales, a veces con intención de identificación interna.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-032","front":"¿Qué es la norma culta?","back":"Es el modelo lingüístico prestigioso usado por hablantes instruidos en situaciones formales, aunque admite diversidad geográfica.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-033","front":"¿Qué es el estándar en lengua española?","back":"Es una variedad supradialectal que sirve de referencia común para la comunicación formal y la enseñanza.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-034","front":"¿Qué función tiene la RAE en relación con el español?","back":"Contribuye a la fijación y orientación de la norma del español, en coordinación con otras academias de la lengua.","topic":"Las lenguas y sus hablantes","difficulty":1,"fromOrientaciones":true},{"id":"lengua-035","front":"¿Qué son los prejuicios lingüísticos?","back":"Son valoraciones negativas o estereotipos sobre una variedad o forma de hablar que no se basan en criterios lingüísticos objetivos.","topic":"Las lenguas y sus hablantes","difficulty":1,"fromOrientaciones":true},{"id":"lengua-036","front":"¿Por qué no debe considerarse inferior una variedad dialectal?","back":"Porque todas las variedades son sistemas válidos de comunicación; su prestigio social no determina su valor lingüístico.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-037","front":"¿Qué es el dialecto andaluz?","back":"Es una modalidad dialectal del español con rasgos fónicos, léxicos y en algunos casos gramaticales propios del ámbito andaluz.","topic":"Las lenguas y sus hablantes","difficulty":1,"fromOrientaciones":true},{"id":"lengua-038","front":"¿Qué es el sefardí?","back":"Es la variedad histórica del castellano conservada por los descendientes de los judíos expulsados de la Península Ibérica.","topic":"Las lenguas y sus hablantes","difficulty":2,"fromOrientaciones":true},{"id":"lengua-039","front":"¿Qué son las lenguas de España?","back":"Son las distintas lenguas presentes en el Estado, entre ellas el castellano y otras lenguas cooficiales o históricas como catalán, gallego y euskera.","topic":"Las lenguas y sus hablantes","difficulty":1,"fromOrientaciones":true},{"id":"lengua-040","front":"¿Qué es una metáfora?","back":"Es una figura retórica que identifica un término con otro por semejanza. Ejemplo: 'Tus ojos son estrellas'.","topic":"Figuras retóricas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-041","front":"¿Qué es una comparación o símil?","back":"Es una figura que relaciona dos elementos mediante un nexo comparativo. Ejemplo: 'Corre como el viento'.","topic":"Figuras retóricas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-042","front":"¿Qué es una personificación?","back":"Consiste en atribuir cualidades o acciones humanas a seres inanimados o abstractos. Ejemplo: 'La ciudad duerme'.","topic":"Figuras retóricas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-043","front":"¿Qué es una hipérbole?","back":"Es una exageración expresiva de la realidad. Ejemplo: 'Te lo he dicho un millón de veces'.","topic":"Figuras retóricas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-044","front":"¿Qué es una anáfora?","back":"Es la repetición de una o varias palabras al comienzo de versos o enunciados. Ejemplo: 'Temprano... temprano... temprano...'.","topic":"Figuras retóricas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-045","front":"¿Qué es un paralelismo?","back":"Es la repetición de estructuras sintácticas semejantes para reforzar el ritmo o el sentido. Ejemplo: 'Quiero reír, quiero vivir'.","topic":"Figuras retóricas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-046","front":"¿Qué es una antítesis?","back":"Es la contraposición de palabras o ideas de significado opuesto. Ejemplo: 'Es tan corto el amor y tan largo el olvido'.","topic":"Figuras retóricas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-047","front":"¿Qué es una enumeración?","back":"Es la sucesión de varios elementos relacionados entre sí. Puede intensificar una descripción o una idea.","topic":"Figuras retóricas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-048","front":"¿Qué es un símbolo literario?","back":"Es un elemento concreto que remite a un significado más profundo y abstracto dentro de la obra.","topic":"Figuras retóricas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-049","front":"¿Qué es el género narrativo?","back":"Es el género literario en el que un narrador cuenta hechos reales o ficticios protagonizados por personajes en un tiempo y espacio.","topic":"Géneros literarios","difficulty":1,"fromOrientaciones":true},{"id":"lengua-050","front":"¿Qué es el género lírico?","back":"Es el género literario en el que predomina la expresión de sentimientos, emociones o reflexiones de un yo poético.","topic":"Géneros literarios","difficulty":1,"fromOrientaciones":true},{"id":"lengua-051","front":"¿Qué es el género dramático?","back":"Es el género literario concebido para la representación escénica, basado en diálogos y acciones de los personajes.","topic":"Géneros literarios","difficulty":1,"fromOrientaciones":true},{"id":"lengua-052","front":"¿Qué es una novela?","back":"Es una narración extensa en prosa que desarrolla una trama compleja con personajes, conflictos y evolución argumental.","topic":"Géneros literarios","difficulty":1,"fromOrientaciones":true},{"id":"lengua-053","front":"¿Qué es un cuento?","back":"Es una narración breve que suele concentrarse en una sola acción, pocos personajes y un desenlace intenso.","topic":"Géneros literarios","difficulty":1,"fromOrientaciones":true},{"id":"lengua-054","front":"¿Qué es una tragedia?","back":"Es un subgénero dramático en el que los conflictos conducen a un desenlace doloroso o fatal.","topic":"Géneros literarios","difficulty":2,"fromOrientaciones":true},{"id":"lengua-055","front":"¿Qué es una comedia?","back":"Es un subgénero dramático de tono generalmente humorístico o crítico que suele terminar de forma favorable.","topic":"Géneros literarios","difficulty":1,"fromOrientaciones":true},{"id":"lengua-056","front":"¿Qué es el Modernismo en la literatura española?","back":"Es un movimiento de renovación estética de finales del XIX y comienzos del XX que busca musicalidad, belleza sensorial y lenguaje cuidado.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-057","front":"¿Qué caracteriza a la Generación del 98?","back":"La preocupación por España, el tono reflexivo, el subjetivismo y la renovación del lenguaje narrativo y ensayístico.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-058","front":"¿Qué caracteriza al Novecentismo o Generación del 14?","back":"Defiende una literatura más intelectual, europeísta y rigurosa, con voluntad de claridad, equilibrio y modernización cultural.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-059","front":"¿Qué fue la Edad de Plata de la cultura española?","back":"Es el periodo de gran esplendor cultural entre finales del XIX y 1936, con figuras clave en literatura, arte y pensamiento.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-060","front":"¿Qué caracteriza a la Generación del 27?","back":"La síntesis entre tradición y vanguardia, el cuidado formal, la metáfora y la variedad temática y estilística.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-061","front":"¿Qué autor se asocia de forma central al teatro lorquiano?","back":"Federico García Lorca, una de las grandes figuras del teatro español del siglo XX por su simbolismo y fuerza poética.","topic":"Literatura","difficulty":1,"fromOrientaciones":true},{"id":"lengua-062","front":"¿Qué consecuencias tuvo la Guerra Civil en la literatura española?","back":"Provocó ruptura cultural, censura, exilio de autores y una profunda transformación temática y estética en narrativa, poesía y teatro.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-063","front":"¿Qué es la literatura del exilio?","back":"Es la producida por autores que, tras la Guerra Civil, escribieron fuera de España manteniendo memoria, crítica y reflexión sobre la pérdida.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-064","front":"¿Qué es el tremendismo en la novela de posguerra?","back":"Es una corriente narrativa de los años cuarenta que presenta ambientes violentos, sórdidos y personajes marcados por la crudeza vital.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-065","front":"¿Qué rasgo define a la novela social de los años cincuenta?","back":"Su atención a la realidad colectiva, la denuncia de desigualdades y el retrato crítico de la vida cotidiana en la posguerra.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-066","front":"¿Qué caracteriza a la novela española desde 1975 hasta hoy?","back":"La diversidad de tendencias, la libertad temática y formal, y la convivencia de novela histórica, intimista, experimental o policíaca.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-067","front":"¿Qué caracteriza a la poesía desde el Modernismo a las vanguardias?","back":"La evolución desde la búsqueda de belleza formal hacia la experimentación, la ruptura estética y la innovación expresiva.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-068","front":"¿Qué caracteriza a la poesía española desde 1939 hasta los años 70?","back":"La sucesión de tendencias como la poesía arraigada, desarraigada, social y de conocimiento, marcadas por el contexto histórico.","topic":"Literatura","difficulty":3,"fromOrientaciones":true},{"id":"lengua-069","front":"¿Qué caracteriza a la poesía española desde los años 70 hasta la actualidad?","back":"La pluralidad estética, la convivencia de corrientes y la apertura a nuevas sensibilidades, lenguajes y experiencias.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-070","front":"¿Qué caracteriza al teatro español desde principios del siglo XX hasta 1939?","back":"La coexistencia de teatro comercial, innovaciones vanguardistas y grandes renovadores como Valle-Inclán y García Lorca.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-071","front":"¿Qué caracteriza al teatro español desde 1939 hasta nuestros días?","back":"La evolución desde el teatro de posguerra y la censura hacia formas de crítica social, experimentación y diversidad escénica.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-072","front":"¿Qué obra de Pío Baroja figura entre las lecturas recomendadas?","back":"El árbol de la ciencia, novela clave para entender la narrativa de la Generación del 98.","topic":"Lecturas recomendadas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-073","front":"¿Qué obra de Luis Cernuda figura entre las lecturas recomendadas?","back":"La realidad y el deseo, título fundamental de la poesía del 27 y de la trayectoria lírica de Cernuda.","topic":"Lecturas recomendadas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-074","front":"¿Qué obra de Federico García Lorca figura entre las lecturas recomendadas?","back":"La casa de Bernarda Alba, drama esencial del teatro español del siglo XX.","topic":"Lecturas recomendadas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-075","front":"¿Qué obra de Carmen Martín Gaite figura entre las lecturas recomendadas?","back":"El cuarto de atrás, novela contemporánea que combina memoria, imaginación y reflexión metaliteraria.","topic":"Lecturas recomendadas","difficulty":1,"fromOrientaciones":true},{"id":"lengua-076","front":"¿Qué relación tiene Federico García Lorca con Andalucía en el temario?","back":"Es uno de los autores andaluces más relevantes y su teatro ocupa un lugar central dentro de la educación literaria.","topic":"Literatura andaluza","difficulty":1,"fromOrientaciones":true},{"id":"lengua-077","front":"¿Qué se entiende por lectura con perspectiva de género?","back":"Es una interpretación que atiende a la representación de mujeres y hombres, las relaciones de poder y los roles sociales en la obra.","topic":"Comentario literario","difficulty":2,"fromOrientaciones":true},{"id":"lengua-078","front":"¿Qué es la intertextualidad?","back":"Es la relación que un texto mantiene con otros textos o manifestaciones artísticas mediante temas, referencias, ecos o reescrituras.","topic":"Comentario literario","difficulty":2,"fromOrientaciones":true},{"id":"lengua-079","front":"¿Qué significa interpretar una obra con ayuda de su contexto sociohistórico?","back":"Relacionar sus temas, personajes y forma con el momento histórico, cultural y artístico en que fue creada.","topic":"Comentario literario","difficulty":2,"fromOrientaciones":true},{"id":"lengua-080","front":"¿Qué valor tiene el metalenguaje específico en literatura y lengua?","back":"Permite analizar textos y fenómenos lingüísticos con precisión usando términos técnicos adecuados como narrador, sujeto, metáfora o cohesión.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-081","front":"¿Qué diferencia existe entre lengua oral y lengua escrita desde el punto de vista sintáctico?","back":"La lengua oral suele presentar mayor espontaneidad, repeticiones e interrupciones; la escrita tiende a estructuras más planificadas y complejas.","topic":"Reflexión sobre la lengua","difficulty":2,"fromOrientaciones":true},{"id":"lengua-082","front":"¿Qué diferencia existe entre lengua oral y lengua escrita desde el punto de vista léxico?","back":"La oral suele ser más coloquial, inmediata y redundante; la escrita suele seleccionar un léxico más preciso y elaborado.","topic":"Reflexión sobre la lengua","difficulty":2,"fromOrientaciones":true},{"id":"lengua-083","front":"¿Qué diferencia existe entre lengua oral y lengua escrita desde el punto de vista pragmático?","back":"La oral depende mucho del contexto compartido y de elementos no verbales; la escrita necesita explicitar más la información.","topic":"Reflexión sobre la lengua","difficulty":2,"fromOrientaciones":true},{"id":"lengua-084","front":"¿Qué son las marcas de lengua escrita en textos hablados?","back":"Son rasgos propios del lenguaje escrito que aparecen en discursos orales, como mayor planificación, sintaxis más cuidada o léxico formal.","topic":"Reflexión sobre la lengua","difficulty":2,"fromOrientaciones":true},{"id":"lengua-085","front":"¿Qué significa que la lengua es un sistema interconectado?","back":"Que sus niveles fonológico, morfológico, sintáctico y semántico se relacionan entre sí y funcionan de forma integrada.","topic":"Reflexión sobre la lengua","difficulty":2,"fromOrientaciones":true},{"id":"lengua-086","front":"¿Qué estudia el nivel fonológico de la lengua?","back":"Estudia los sonidos con valor distintivo en una lengua y su funcionamiento dentro del sistema.","topic":"Gramática","difficulty":1,"fromOrientaciones":true},{"id":"lengua-087","front":"¿Qué estudia el nivel morfológico de la lengua?","back":"Estudia la estructura de las palabras, sus formantes y los procedimientos de formación.","topic":"Gramática","difficulty":1,"fromOrientaciones":true},{"id":"lengua-088","front":"¿Qué estudia el nivel sintáctico de la lengua?","back":"Estudia cómo se combinan las palabras en grupos y oraciones, y qué funciones desempeñan.","topic":"Gramática","difficulty":1,"fromOrientaciones":true},{"id":"lengua-089","front":"¿Qué estudia el nivel semántico de la lengua?","back":"Estudia el significado de las palabras, expresiones y estructuras lingüísticas.","topic":"Gramática","difficulty":1,"fromOrientaciones":true},{"id":"lengua-090","front":"¿Qué diferencia hay entre diacronía y sincronía?","back":"La diacronía estudia la evolución de la lengua a lo largo del tiempo; la sincronía la analiza en un momento determinado.","topic":"Reflexión sobre la lengua","difficulty":2,"fromOrientaciones":true},{"id":"lengua-091","front":"¿Qué diferencia hay entre categoría gramatical y función sintáctica?","back":"La categoría indica qué tipo de palabra es; la función señala el papel que desempeña dentro de la oración.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-092","front":"¿Qué es un grupo sintáctico?","back":"Es una unidad formada por una palabra núcleo y, a veces, otros elementos que la acompañan y dependen de ella.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-093","front":"¿Qué es el sujeto de una oración?","back":"Es la función sintáctica que concuerda normalmente con el verbo en número y persona y designa de quién se dice algo.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-094","front":"¿Qué es el predicado de una oración?","back":"Es la función sintáctica que expresa lo que se dice del sujeto y cuyo núcleo suele ser un verbo.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-095","front":"¿Qué es el complemento directo?","back":"Es la función que recibe directamente la acción del verbo. En muchos casos puede sustituirse por 'lo', 'la', 'los' o 'las'.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-096","front":"¿Qué es el complemento indirecto?","back":"Es la función que expresa el destinatario o beneficiario de la acción verbal y suele sustituirse por 'le' o 'les'.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-097","front":"¿Qué es el complemento de régimen?","back":"Es un complemento exigido por ciertos verbos y va introducido por una preposición fija: por ejemplo, 'confiar en algo'.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-098","front":"¿Qué es el complemento circunstancial?","back":"Es la función que indica circunstancias de la acción verbal, como lugar, tiempo, modo, causa o finalidad.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-099","front":"¿Qué es el atributo en una oración copulativa?","back":"Es el complemento que expresa una cualidad o identificación del sujeto con verbos como ser, estar o parecer.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-100","front":"¿Qué es el complemento predicativo?","back":"Es un complemento que aporta una cualidad referida al sujeto o al complemento directo y concuerda con él.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-101","front":"¿Qué son las funciones extraoracionales?","back":"Son elementos que no se integran en la estructura básica sujeto-predicado, como vocativos, marcadores discursivos o incisos.","topic":"Sintaxis","difficulty":3,"fromOrientaciones":true},{"id":"lengua-102","front":"¿Qué son los valores del 'se'?","back":"Son los distintos usos de 'se', como pronombre reflexivo, recíproco, dativo, pasiva refleja, impersonal o marca verbal.","topic":"Sintaxis","difficulty":3,"fromOrientaciones":true},{"id":"lengua-103","front":"¿Qué es una oración coordinada?","back":"Es una oración compuesta formada por proposiciones de igual nivel sintáctico unidas por nexos como 'y', 'o' o 'pero'.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-104","front":"¿Qué es una oración yuxtapuesta?","back":"Es una oración compuesta cuyas proposiciones aparecen unidas sin nexos, normalmente mediante signos de puntuación.","topic":"Sintaxis","difficulty":1,"fromOrientaciones":true},{"id":"lengua-105","front":"¿Qué es una subordinada sustantiva?","back":"Es una proposición subordinada que desempeña funciones propias de un sustantivo, como sujeto o complemento directo.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-106","front":"¿Qué es una subordinada adjetiva o de relativo?","back":"Es una proposición subordinada que complementa a un sustantivo y funciona de modo parecido a un adjetivo.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-107","front":"¿Qué es una subordinada adverbial?","back":"Es una proposición subordinada que expresa circunstancias como tiempo, modo, causa, condición o finalidad.","topic":"Sintaxis","difficulty":2,"fromOrientaciones":true},{"id":"lengua-108","front":"¿Qué relación existe entre estructura semántica y estructura sintáctica en la oración?","back":"El significado del verbo y sus argumentos condiciona la organización sintáctica de sujeto, predicado y complementos.","topic":"Sintaxis","difficulty":3,"fromOrientaciones":true},{"id":"lengua-109","front":"¿Qué son los argumentos de un verbo?","back":"Son los elementos exigidos por su significado para completar la predicación, como sujeto, complemento directo o suplemento.","topic":"Sintaxis","difficulty":3,"fromOrientaciones":true},{"id":"lengua-110","front":"¿Qué es la derivación en la formación de palabras?","back":"Es el procedimiento por el que se crean palabras añadiendo prefijos o sufijos a una base léxica.","topic":"Morfología","difficulty":1,"fromOrientaciones":true},{"id":"lengua-111","front":"¿Qué es la composición en la formación de palabras?","back":"Es el procedimiento por el que se forma una palabra nueva mediante la unión de dos o más lexemas.","topic":"Morfología","difficulty":1,"fromOrientaciones":true},{"id":"lengua-112","front":"¿Qué es la parasíntesis?","back":"Es un procedimiento de formación que combina simultáneamente composición y derivación, o prefijación y sufijación inseparables.","topic":"Morfología","difficulty":3,"fromOrientaciones":true},{"id":"lengua-113","front":"¿Qué es un lexema?","back":"Es la parte de la palabra que aporta el significado básico o léxico.","topic":"Morfología","difficulty":1,"fromOrientaciones":true},{"id":"lengua-114","front":"¿Qué es un morfema?","back":"Es la unidad mínima con significado gramatical o léxico que se añade al lexema o lo acompaña.","topic":"Morfología","difficulty":1,"fromOrientaciones":true},{"id":"lengua-115","front":"¿Qué es un prefijo?","back":"Es un morfema derivativo que se coloca delante del lexema para modificar su significado.","topic":"Morfología","difficulty":1,"fromOrientaciones":true},{"id":"lengua-116","front":"¿Qué es un sufijo?","back":"Es un morfema derivativo que se añade detrás del lexema y puede crear nuevas palabras o matizar su significado.","topic":"Morfología","difficulty":1,"fromOrientaciones":true},{"id":"lengua-117","front":"¿Qué es la sinonimia?","back":"Es la relación semántica entre palabras de significado semejante, aunque no siempre idéntico en todos los contextos.","topic":"Semántica","difficulty":1,"fromOrientaciones":true},{"id":"lengua-118","front":"¿Qué es la antonimia?","back":"Es la relación semántica entre palabras de significado opuesto, como 'alto' y 'bajo'.","topic":"Semántica","difficulty":1,"fromOrientaciones":true},{"id":"lengua-119","front":"¿Qué es la polisemia?","back":"Es la propiedad por la que una misma palabra puede tener varios significados relacionados entre sí.","topic":"Semántica","difficulty":1,"fromOrientaciones":true},{"id":"lengua-120","front":"¿Qué es la homonimia?","back":"Es la coincidencia formal entre palabras distintas que tienen significados diferentes y origen no necesariamente común.","topic":"Semántica","difficulty":2,"fromOrientaciones":true},{"id":"lengua-121","front":"¿Qué es un campo semántico?","back":"Es el conjunto de palabras de la misma categoría gramatical que comparten un rasgo de significado común.","topic":"Semántica","difficulty":2,"fromOrientaciones":true},{"id":"lengua-122","front":"¿Qué es un campo asociativo?","back":"Es el conjunto de palabras que se relacionan con una idea por asociación cultural o contextual, aunque no pertenezcan a la misma categoría.","topic":"Semántica","difficulty":2,"fromOrientaciones":true},{"id":"lengua-123","front":"¿Qué diferencia hay entre significado denotativo y connotativo?","back":"El denotativo es el significado básico y objetivo; el connotativo añade valores subjetivos, culturales o afectivos.","topic":"Semántica","difficulty":2,"fromOrientaciones":true},{"id":"lengua-124","front":"¿Qué es un mecanismo de cohesión léxica?","back":"Es un recurso que enlaza partes del texto mediante repetición, sinonimia, hiperonimia o campos semánticos.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-125","front":"¿Qué es un mecanismo de cohesión gramatical?","back":"Es un recurso que conecta elementos del texto mediante pronombres, elipsis, deícticos, conectores o correlación verbal.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-126","front":"¿Qué función tienen los tiempos verbales en la cohesión del texto?","back":"Ayudan a organizar temporalmente la información y a mantener la continuidad o contraste entre las ideas.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-127","front":"¿Qué valor pueden tener las formas no personales del verbo en un texto?","back":"Aportan condensación informativa, matices aspectuales y relaciones sintácticas sin necesidad de flexión personal.","topic":"Gramática","difficulty":3,"fromOrientaciones":true},{"id":"lengua-128","front":"¿Qué es una perífrasis verbal?","back":"Es una construcción formada por un verbo auxiliar y una forma no personal que expresa matices de aspecto o modalidad.","topic":"Gramática","difficulty":2,"fromOrientaciones":true},{"id":"lengua-129","front":"¿Qué es una transformación gramatical en un ejercicio de lengua?","back":"Es la modificación de una estructura del texto sin alterar su sentido esencial, como pasar de activa a pasiva o de estilo directo a indirecto.","topic":"Gramática","difficulty":2,"fromOrientaciones":true},{"id":"lengua-130","front":"¿Qué aporta el análisis de dos palabras de un texto desde la morfología?","back":"Permite identificar sus formantes, su procedimiento de creación y el valor significativo de sus componentes.","topic":"Morfología","difficulty":2,"fromOrientaciones":true},{"id":"lengua-131","front":"¿Qué significa explicar el sentido de una palabra dentro del texto?","back":"Interpretarla según el contexto concreto, no solo según su definición de diccionario.","topic":"Semántica","difficulty":1,"fromOrientaciones":true},{"id":"lengua-132","front":"¿Qué es una marca de objetividad en un texto?","back":"Es un rasgo lingüístico que reduce la implicación personal del emisor, como el uso de datos, tercera persona o construcciones impersonales.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-133","front":"¿Qué es una marca de subjetividad en un texto?","back":"Es un rasgo lingüístico que muestra la postura del emisor, como valoraciones, modalizadores o expresiones afectivas.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-134","front":"¿Qué debe hacerse al comentar un mecanismo de cohesión en un texto?","back":"Identificarlo, citarlo y explicar cómo contribuye a relacionar ideas y reforzar la coherencia global.","topic":"Comentario de texto","difficulty":2,"fromOrientaciones":true},{"id":"lengua-135","front":"¿Qué caracteriza a la novela española de principios del siglo XX hasta 1939?","back":"La convivencia de la narrativa del 98, el Novecentismo y otras fórmulas renovadoras preocupadas por estilo, reflexión y técnica.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-136","front":"¿Qué autor y obra son representativos de la narrativa de la Generación del 98?","back":"Pío Baroja y El árbol de la ciencia son una referencia esencial de la narrativa noventayochista.","topic":"Literatura","difficulty":1,"fromOrientaciones":true},{"id":"lengua-137","front":"¿Qué rasgo estilístico suele aparecer en la narrativa de la Generación del 98?","back":"La sobriedad expresiva, la reflexión existencial y la atención crítica a la realidad española.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-138","front":"¿Qué autor puede asociarse a la novela novecentista en España?","back":"Ramón Pérez de Ayala es uno de los autores vinculados al Novecentismo narrativo por su enfoque intelectual.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-139","front":"¿Qué autor y obra representan el tremendismo de posguerra?","back":"Camilo José Cela y La familia de Pascual Duarte son la referencia más habitual de esta corriente.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-140","front":"¿Qué rasgos presenta la novela existencial de los años cuarenta?","back":"Refleja angustia, soledad, frustración y una visión pesimista de la vida en la inmediata posguerra.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-141","front":"¿Qué autores destacan en la novela social de los años cincuenta?","back":"Sobresalen autores como Camilo José Cela, Miguel Delibes, Rafael Sánchez Ferlosio o Carmen Martín Gaite.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-142","front":"¿Qué caracteriza a la poesía del grupo poético del 27 en su primera etapa?","back":"Predominan la poesía pura, el cuidado formal y la influencia de Góngora y de las vanguardias.","topic":"Literatura","difficulty":3,"fromOrientaciones":true},{"id":"lengua-143","front":"¿Qué autor es una figura central de la poesía del 27 y aparece en las lecturas recomendadas?","back":"Luis Cernuda, cuya obra La realidad y el deseo es clave para el estudio del grupo y de su evolución poética.","topic":"Literatura","difficulty":1,"fromOrientaciones":true},{"id":"lengua-144","front":"¿Qué papel ocupa Juan Ramón Jiménez en el marco literario del temario?","back":"Es una figura esencial en la renovación poética del primer tercio del siglo XX y un referente para generaciones posteriores.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-145","front":"¿Qué caracteriza al teatro lorquiano?","back":"La combinación de lirismo, simbolismo, conflicto trágico y crítica de normas sociales opresivas.","topic":"Literatura","difficulty":2,"fromOrientaciones":true},{"id":"lengua-146","front":"¿Qué conflicto central aparece en La casa de Bernarda Alba?","back":"El enfrentamiento entre autoridad y deseo, especialmente entre la represión impuesta por Bernarda y la libertad anhelada por sus hijas.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-147","front":"¿Qué representa Bernarda Alba dentro de la obra?","back":"Representa la autoridad, el control social, el autoritarismo y la defensa obsesiva del honor y las apariencias.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-148","front":"¿Qué representa Adela en La casa de Bernarda Alba?","back":"Representa la rebeldía, el deseo de libertad y la oposición a la represión moral y familiar.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-149","front":"¿Qué representa Martirio en La casa de Bernarda Alba?","back":"Encierra frustración, resentimiento y conflicto interno, y actúa como figura clave en la tensión que conduce al final trágico.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-150","front":"¿Qué representa María Josefa en La casa de Bernarda Alba?","back":"Representa la verdad, el deseo de libertad y una voz simbólica que expresa lo que la casa reprime.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-151","front":"¿Qué simboliza el bastón en La casa de Bernarda Alba?","back":"Simboliza el poder autoritario de Bernarda, la imposición de la norma y el control sobre la casa.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-152","front":"¿Qué simboliza el caballo en La casa de Bernarda Alba?","back":"Simboliza la fuerza del deseo sexual y vital que intenta romper la represión dominante en la casa.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-153","front":"¿Qué aporta el fragmento literario al comentario de una obra?","back":"Permite relacionar un pasaje concreto con los temas, personajes, símbolos, estructura y contexto de toda la obra.","topic":"Comentario literario","difficulty":2,"fromOrientaciones":true},{"id":"lengua-154","front":"¿Qué rasgo define la poesía de Luis Cernuda?","back":"La tensión entre deseo y realidad, junto con un tono íntimo, reflexivo y profundamente personal.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-155","front":"¿Qué rasgo define El árbol de la ciencia de Pío Baroja?","back":"Su visión crítica y pesimista de la sociedad, unida a la reflexión existencial del protagonista.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-156","front":"¿Qué rasgo define El cuarto de atrás de Carmen Martín Gaite?","back":"Combina memoria, ficción, reflexión sobre la escritura y evocación del pasado desde una estructura original.","topic":"Lecturas recomendadas","difficulty":2,"fromOrientaciones":true},{"id":"lengua-157","front":"¿Qué importancia tienen los autores andaluces en las orientaciones de Literatura?","back":"Reciben una atención especial como referentes culturales, con énfasis en autores del siglo XX y XXI vinculados a Andalucía.","topic":"Literatura andaluza","difficulty":2,"fromOrientaciones":true},{"id":"lengua-158","front":"¿Qué permite la creación de textos de intención literaria a partir de obras leídas?","back":"Favorece la comprensión profunda de recursos, temas y estilos mediante una apropiación creativa de los modelos literarios.","topic":"Educación literaria","difficulty":2,"fromOrientaciones":true},{"id":"lengua-159","front":"¿Qué valor tiene la lectura expresiva, dramatización y recitado en educación literaria?","back":"Ayudan a comprender mejor el texto, su ritmo, su tono y su dimensión oral o escénica.","topic":"Educación literaria","difficulty":2,"fromOrientaciones":true},{"id":"lengua-160","front":"¿Qué debe integrar una buena interpretación literaria?","back":"Debe relacionar tema, forma, contexto, género, recursos expresivos y valores culturales, éticos y estéticos de la obra.","topic":"Comentario literario","difficulty":3,"fromOrientaciones":true}]`),i={subject:e,flashcards:a};export{i as default,a as flashcards,e as subject};
